c_widget_StreakWidget_kt = 'package com.sujood.app.widget\n\nimport android.content.Context\nimport androidx.compose.runtime.Composable\nimport androidx.compose.ui.graphics.Color\nimport androidx.compose.ui.unit.dp\nimport androidx.compose.ui.unit.sp\nimport androidx.glance.GlanceId\nimport androidx.glance.GlanceModifier\nimport androidx.glance.action.actionStartActivity\nimport androidx.glance.action.clickable\nimport androidx.glance.appwidget.GlanceAppWidget\nimport androidx.glance.appwidget.GlanceAppWidgetReceiver\nimport androidx.glance.appwidget.cornerRadius\nimport androidx.glance.appwidget.provideContent\nimport androidx.glance.background\nimport androidx.glance.layout.Alignment\nimport androidx.glance.layout.Box\nimport androidx.glance.layout.Column\nimport androidx.glance.layout.Row\nimport androidx.glance.layout.Spacer\nimport androidx.glance.layout.fillMaxSize\nimport androidx.glance.layout.fillMaxWidth\nimport androidx.glance.layout.height\nimport androidx.glance.layout.padding\nimport androidx.glance.layout.size\nimport androidx.glance.layout.width\nimport androidx.glance.layout.wrapContentHeight\nimport androidx.glance.state.GlanceStateDefinition\nimport androidx.glance.state.PreferencesGlanceStateDefinition\nimport androidx.glance.text.FontWeight\nimport androidx.glance.text.Text\nimport androidx.glance.text.TextStyle\nimport androidx.glance.unit.ColorProvider\nimport com.sujood.app.MainActivity\nimport com.sujood.app.data.local.datastore.UserPreferences\nimport kotlinx.coroutines.flow.first\n\nclass StreakWidget : GlanceAppWidget() {\n    override val stateDefinition: GlanceStateDefinition<*> = PreferencesGlanceStateDefinition\n\n    override suspend fun provideGlance(context: Context, id: GlanceId) {\n        val prefs     = UserPreferences(context)\n        val settings  = prefs.userSettings.first()\n        val streak    = settings.streakDays\n        val completed = settings.completedPrayersToday.size\n\n        provideContent { StreakWidgetContent(streak, completed) }\n    }\n}\n\n@Composable\nprivate fun StreakWidgetContent(streak: Int, completed: Int) {\n    val total   = 5\n    val bg      = ColorProvider(Color(0xFF0D1020))\n    val blue    = ColorProvider(Color(0xFF3B82F6))\n    val blueDim = ColorProvider(Color(0xFF1D4ED8))\n    val white   = ColorProvider(Color.White)\n    val muted   = ColorProvider(Color(0xFF475569))\n    val empty   = ColorProvider(Color(0xFF1E293B))\n    val gold    = ColorProvider(Color(0xFFFBBF24))\n    val allDone = completed == total\n\n    Box(\n        modifier = GlanceModifier\n            .fillMaxSize()\n            .background(bg)\n            .cornerRadius(20.dp)\n            .clickable(actionStartActivity<MainActivity>())\n            .padding(18.dp),\n        contentAlignment = Alignment.TopStart\n    ) {\n        Column(modifier = GlanceModifier.fillMaxSize()) {\n            // Label\n            Text(\n                "PRAYER STREAK",\n                style = TextStyle(color = blue, fontSize = 9.sp, fontWeight = FontWeight.Bold)\n            )\n            Spacer(GlanceModifier.height(8.dp))\n            // Big number\n            Row(verticalAlignment = Alignment.Bottom) {\n                Text(\n                    "$streak",\n                    style = TextStyle(\n                        color = if (allDone) gold else white,\n                        fontSize = 40.sp,\n                        fontWeight = FontWeight.Bold\n                    )\n                )\n                Spacer(GlanceModifier.width(5.dp))\n                Text(\n                    "day streak",\n                    style = TextStyle(color = muted, fontSize = 12.sp)\n                )\n            }\n            Spacer(GlanceModifier.height(12.dp))\n            // Prayer dots row\n            Row(modifier = GlanceModifier.fillMaxWidth()) {\n                for (i in 0 until total) {\n                    val done = i < completed\n                    Box(\n                        modifier = GlanceModifier\n                            .size(width = 0.dp, height = 6.dp)\n                            .defaultWeight()\n                            .background(if (done) blueDim else empty)\n                            .cornerRadius(3.dp)\n                    ) {}\n                    if (i < total - 1) Spacer(GlanceModifier.width(4.dp))\n                }\n            }\n            Spacer(GlanceModifier.height(7.dp))\n            // Status text\n            Text(\n                if (allDone) "All 5 prayers complete today ✓"\n                else "$completed / $total prayers today",\n                style = TextStyle(\n                    color = if (allDone) gold else muted,\n                    fontSize = 11.sp,\n                    fontWeight = if (allDone) FontWeight.Bold else FontWeight.Normal\n                )\n            )\n        }\n    }\n}\n\nclass StreakWidgetReceiver : GlanceAppWidgetReceiver() {\n    override val glanceAppWidget: GlanceAppWidget = StreakWidget()\n}\n'
p = os.path.join(ROOT, 'Sujood', 'app', 'src', 'main', 'java', 'com', 'sujood', 'app', 'widget', 'StreakWidget.kt')
os.makedirs(os.path.dirname(p), exist_ok=True)
open(p,'w',encoding='utf-8',newline='\n').write(c_widget_StreakWidget_kt)
print('DONE StreakWidget.kt')

c_widget_AyahWidget_kt = 'package com.sujood.app.widget\n\nimport android.content.Context\nimport androidx.compose.runtime.Composable\nimport androidx.compose.ui.graphics.Color\nimport androidx.compose.ui.unit.dp\nimport androidx.compose.ui.unit.sp\nimport androidx.glance.GlanceId\nimport androidx.glance.GlanceModifier\nimport androidx.glance.action.actionStartActivity\nimport androidx.glance.action.clickable\nimport androidx.glance.appwidget.GlanceAppWidget\nimport androidx.glance.appwidget.GlanceAppWidgetReceiver\nimport androidx.glance.appwidget.cornerRadius\nimport androidx.glance.appwidget.provideContent\nimport androidx.glance.background\nimport androidx.glance.layout.Alignment\nimport androidx.glance.layout.Box\nimport androidx.glance.layout.Column\nimport androidx.glance.layout.Row\nimport androidx.glance.layout.Spacer\nimport androidx.glance.layout.fillMaxSize\nimport androidx.glance.layout.fillMaxWidth\nimport androidx.glance.layout.height\nimport androidx.glance.layout.padding\nimport androidx.glance.layout.size\nimport androidx.glance.layout.width\nimport androidx.glance.state.GlanceStateDefinition\nimport androidx.glance.state.PreferencesGlanceStateDefinition\nimport androidx.glance.text.FontStyle\nimport androidx.glance.text.FontWeight\nimport androidx.glance.text.Text\nimport androidx.glance.text.TextStyle\nimport androidx.glance.unit.ColorProvider\nimport com.sujood.app.MainActivity\nimport java.util.Calendar\n\nprivate val AYAHS = listOf(\n    Pair("Verily, with hardship comes ease.", "Ash-Sharh 94:6"),\n    Pair("Indeed, prayer prohibits immorality and wrongdoing.", "Al-Ankabut 29:45"),\n    Pair("And seek help through patience and prayer.", "Al-Baqarah 2:45"),\n    Pair("Allah does not burden a soul beyond that it can bear.", "Al-Baqarah 2:286"),\n    Pair("Establish prayer for My remembrance.", "Ta-Ha 20:14"),\n    Pair("Remember Me and I will remember you.", "Al-Baqarah 2:152"),\n    Pair("Verily, in the remembrance of Allah do hearts find rest.", "Ar-Ra\'d 13:28"),\n    Pair("He is with you wherever you are.", "Al-Hadid 57:4"),\n    Pair("So be patient. Indeed, the promise of Allah is truth.", "Ar-Rum 30:60"),\n    Pair("Call upon Me; I will respond to you.", "Ghafir 40:60"),\n    Pair("My mercy encompasses all things.", "Al-A\'raf 7:156"),\n    Pair("Allah is sufficient for us, and He is the best disposer of affairs.", "Al-Imran 3:173"),\n    Pair("Do not despair of the mercy of Allah.", "Az-Zumar 39:53"),\n    Pair("Whoever fears Allah, He will make a way out for him.", "At-Talaq 65:2")\n)\n\nclass AyahWidget : GlanceAppWidget() {\n    override val stateDefinition: GlanceStateDefinition<*> = PreferencesGlanceStateDefinition\n\n    override suspend fun provideGlance(context: Context, id: GlanceId) {\n        val dayOfYear = Calendar.getInstance().get(Calendar.DAY_OF_YEAR)\n        val ayah = AYAHS[dayOfYear % AYAHS.size]\n        provideContent { AyahWidgetContent(verse = ayah.first, reference = ayah.second) }\n    }\n}\n\n@Composable\nprivate fun AyahWidgetContent(verse: String, reference: String) {\n    val bg      = ColorProvider(Color(0xFF0A0C1A))\n    val purple  = ColorProvider(Color(0xFF8B5CF6))\n    val purDim  = ColorProvider(Color(0xFF4C1D95).copy(alpha = 0.6f))\n    val textCol = ColorProvider(Color(0xFFE2E8F0))\n    val muted   = ColorProvider(Color(0xFF64748B))\n    val white   = ColorProvider(Color.White)\n\n    Box(\n        modifier = GlanceModifier\n            .fillMaxSize()\n            .background(bg)\n            .cornerRadius(20.dp)\n            .clickable(actionStartActivity<MainActivity>())\n            .padding(18.dp),\n        contentAlignment = Alignment.TopStart\n    ) {\n        Column(modifier = GlanceModifier.fillMaxSize()) {\n            // Header row\n            Row(verticalAlignment = Alignment.CenterVertically) {\n                // Quote badge\n                Box(\n                    modifier = GlanceModifier\n                        .size(26.dp)\n                        .background(purDim)\n                        .cornerRadius(8.dp),\n                    contentAlignment = Alignment.Center\n                ) {\n                    Text(\n                        text = "❝",\n                        style = TextStyle(color = purple, fontSize = 13.sp, fontWeight = FontWeight.Bold)\n                    )\n                }\n                Spacer(GlanceModifier.width(8.dp))\n                Text(\n                    "AYAH OF THE DAY",\n                    style = TextStyle(color = purple, fontSize = 9.sp, fontWeight = FontWeight.Bold)\n                )\n            }\n            Spacer(GlanceModifier.height(12.dp))\n            // Verse text\n            Text(\n                verse,\n                style = TextStyle(\n                    color = textCol,\n                    fontSize = 12.sp,\n                    fontStyle = FontStyle.Italic\n                )\n            )\n            Spacer(GlanceModifier.defaultWeight())\n            // Reference\n            Row(verticalAlignment = Alignment.CenterVertically) {\n                Box(\n                    modifier = GlanceModifier\n                        .size(width = 3.dp, height = 14.dp)\n                        .background(purple)\n                        .cornerRadius(2.dp)\n                ) {}\n                Spacer(GlanceModifier.width(7.dp))\n                Text(\n                    reference,\n                    style = TextStyle(color = muted, fontSize = 10.sp, fontWeight = FontWeight.Bold)\n                )\n            }\n        }\n    }\n}\n\nclass AyahWidgetReceiver : GlanceAppWidgetReceiver() {\n    override val glanceAppWidget: GlanceAppWidget = AyahWidget()\n}\n'
